#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    int search(vector<int>& nums, int start, int end, int target) {
        if (start > end) return -1;
        int mid = start + (end - start) / 2;
        if (nums[mid] == target) return mid;
        if (nums[start] <= nums[end]) {
            if (nums[start] <= target && target <= nums[mid]) return search(nums, start, mid, target);
            return search(nums, mid + 1, end, target);
        } else {
            if (nums[mid] <= target && target <= nums[end]) return search(nums, mid + 1, end, target);
            return search(nums, start, mid, target);
        }
        return -1;
    }
};
int main() {
    vector<int> nums = {4, 5, 6, 7, 0, 1, 2};
    Solution solution;
    cout << solution.search(nums, 0, nums.size() - 1, 0) << endl;
    return 0;
}
